  ('islands-6f0ba476-moex-00044', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '所有人對於無權占有或侵奪其所有物者，得請求返還之。下列何者非屬有權占有？', '["動產質權關係", "抵押權關係", "寄託關係", "租賃關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00045', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲男乙女為夫妻，甲乙有一子丙，丙未婚。乙妹為丁，丁夫為戊，丁戊收養一女為庚，庚未婚。 戊之弟為辛，辛未婚。甲於民國112年3月間死亡。關於禁婚親及禁止近親收養之規定，下列敘 述何者錯誤？', '["乙與辛非屬禁婚親", "丙與庚非屬禁婚親", "戊與乙屬禁止收養之親屬", "戊與丙屬禁止收養之親屬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00046', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '下列何者為要式行為？', '["家庭生活費用負擔之約定", "子女姓氏之約定", "婚姻住所之約定", "子女親權人之約定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00047', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲與乙結婚後，居住於乙之父丙所有之房屋中。此外，同居此屋者尚有丙之交往對象丁，以及丙 之女（亦即乙之妹）戊。假設甲、乙、丁、戊均不能維持生活而無謀生能力。丙雖有扶養能力， 但其經濟能力，不足扶養其全體時，何者得最優先請求丙扶養？', '["甲、乙", "乙、戊、丁", "乙、戊", "丁"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00048', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲乙結婚後，生下一女丙，不幸早夭。甲死亡時，除與配偶乙共同生活，尚同時照顧甲之祖母丁 與甲之外祖父戊。關於甲之遺產，下列敘述何者正確？', '["乙可得三分之二", "丙可得四分之一", "丁可得三分之一", "戊可得二分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00049', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '設甲於民國110年10月間死亡，有繼承人二人為乙、丙。乙為有行為能力人，丙為限制行為能 力人。甲生前立遺囑，將珍藏之骨董遺贈於好友丁。甲生前向債權人戊借款新臺幣（下同）300 萬元仍未清償。甲死亡時，留有存款100萬元。關於甲遺產之繼承，下列敘述何者正確？', '["乙與丙如依民法規定，開具遺產清冊陳報法院後，乙與丙對甲生前向戊借300萬元仍未清償之 債務，不負任何清償責任", "乙若在遺產清冊為虛偽之記載情節重大，乙則喪失其繼承權", "乙如已依民法規定，開具遺產清冊陳報法院，丙則視為已陳報", "如甲之遺囑有效，乙丙應先將骨董交付丁後，始得對戊為清償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00050', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲有乙丙兩子，甲死亡後，由乙丙共同繼承甲之遺產，其後並為遺產之分割。甲之遺產分割費用， 應從何處支付？', '["甲之遺產中", "乙之固有財產中", "丙之固有財產中", "乙之固有財產與丙之固有財產中"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00051', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'essay', '關於我國營利事業所得稅暫繳申報，請依我國現行所得稅法及其相關法
規規定，回答下列問題：
採七月制的公司，應於何時辦理暫繳申報？又依所得稅法第 67 條第 3
項規定，營利事業應符合那些條件始得採行試算暫繳申報？請說明之。
（10分）
設乙公司採曆年制，其113年度結算申報應納稅額480萬元。114年乙
公司辦理暫繳申報時，有短期票券之利息所得之扣繳稅款 20 萬元；另
該公司114年上半年資料：營業收入9,800萬元、營業成本4,500萬元、
營業費用2,800萬元、非營業收入110萬元、非營業損失80萬元。
假設乙公司符合採試算暫繳之規定並採用之。試問乙公司114年度之應
納暫繳稅額與應自行向公庫補繳之暫繳稅額各為多少金額？（15 分）
（未詳列計算式不予計分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00052', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'essay', '甲公司為總公司在我國的營利事業，其對於位在低稅負國家的 A公司之
持股比率有 80%，而 A公司則 100%持有另一家 B公司（位於大陸地區
以外的非低稅負國家）。X1 年度 B 公司財報稅後盈餘為 1,000 萬元，年
中決議分配股利900 萬元，並已匯出；而同年，A公司財務報表稅後盈
餘僅認列 B公司的投資收益，無其他所得，且 A公司 X1 年決議不分配
股利。甲公司 X1年度之國內所得為 400萬元、不含 CFC 投資收益的其
他國外所得 800萬元（該國外所得於所得來源國已納所得稅 180萬元）。
假設 A公司當地法令規定股利匯出扣繳所得稅率為 10%，B公司當地規
定之股利匯出扣繳所得稅率為 20%。
試問：
甲公司 X1 年度應認列多少來自於 A 公司的受控外國公司的投資收益
金額（假設所有持股期間皆大於1 年）？（10分）
甲公司 X1年度營利事業所得稅之國外可扣抵稅額上限？（10分）
甲公司 X1年度全部之應納營利事業所得稅額？（5分）
