  ('islands-6f0ba476-moex-00053', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '下列有關稅捐核課期間之起算，何者錯誤？', '["依法應由納稅義務人申報繳納之稅捐，未在規定期間內申報繳納者，自規定申報期間屆滿之日 起算", "依法應由納稅義務人申報繳納之稅捐，已在規定期間內申報者，自申報日起算", "土地增值稅自稅捐稽徵機關收件日起算", "印花稅自依法應貼用印花稅票日起算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL)
